import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"中美能源（伯克希尔能源）","description":"","frontmatter":{"title":"中美能源（伯克希尔能源）"},"headers":[],"relativePath":"03_companies/中美能源.md","filePath":"03_companies/中美能源.md"}'),i={name:"03_companies/中美能源.md"};function h(d,t,o,s,n,_){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="中美能源-伯克希尔能源" tabindex="-1">中美能源（伯克希尔能源） <a class="header-anchor" href="#中美能源-伯克希尔能源" aria-label="Permalink to &quot;中美能源（伯克希尔能源）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 1999年</li><li><strong>持股情况</strong>: <ul><li>1999年：伯克希尔投资约20亿美元</li><li>2000年：伯克希尔持股76%（监管限制投票权）</li><li>2003年：伯克希尔持股80.2%</li><li>2020年：伯克希尔持有91%股权</li><li>2024年：从约92%提高到100%</li></ul></li><li><strong>行业</strong>: 能源公用事业</li><li><strong>英文名</strong>: MidAmerican Energy / Berkshire Hathaway Energy (BHE)</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>1999年投资约20亿美元进入公用事业领域。后更名为伯克希尔哈撒韦能源(BHE)，成为伯克希尔的&quot;四大珍宝&quot;之一。</p><p>这是一家非常不寻常的公用事业企业。在英国服务360万客户，是英国第三大电力分销商。2002年中美能源收购Kern River天然气管道和Northern Natural Gas（16,600英里天然气管道）。2005年收购PacifiCorp，服务西部六个州160万电力客户。2013年以56亿美元收购NV Energy，服务内华达州约88%人口。</p><p>在21年间年度收益从1.22亿美元（2000年）增长到34亿美元（2020年）。是美国大部分地区风能、太阳能和输电领域的领导力量。正在进行180亿美元的西部输电项目（2006年启动，预计2030年完成）。</p><h2 id="收益变化" tabindex="-1">收益变化 <a class="header-anchor" href="#收益变化" aria-label="Permalink to &quot;收益变化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>收益</th></tr></thead><tbody><tr><td>2000年</td><td>1.22亿美元</td></tr><tr><td>2020年</td><td>34亿美元</td></tr><tr><td>2021年</td><td>40亿美元</td></tr><tr><td>2022年</td><td>43亿美元</td></tr><tr><td>2023年</td><td>23.31亿美元</td></tr><tr><td>2024年</td><td>37.30亿美元</td></tr></tbody></table><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>1999, 2000, 2002, 2003, 2005, 2006, 2010, 2013, 2020, 2021, 2022, 2023, 2024</p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2000年/翻译.html">2000年</a></li><li><a href="./../01_letters/2002年/翻译.html">2002年</a></li><li><a href="./../01_letters/2003年/翻译.html">2003年</a></li><li><a href="./../01_letters/2004年/翻译.html">2004年</a></li><li><a href="./../01_letters/2005年/翻译.html">2005年</a></li><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2007年/翻译.html">2007年</a></li><li><a href="./../01_letters/2008年/翻译.html">2008年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li><li><a href="./../01_letters/2011年/翻译.html">2011年</a></li><li><a href="./../01_letters/2012年/翻译.html">2012年</a></li><li><a href="./../01_letters/2013年/翻译.html">2013年</a></li><li><a href="./../01_letters/2017年/翻译.html">2017年</a></li></ul>',13)])])}const f=a(i,[["render",h]]);export{c as __pageData,f as default};
